import{_ as e,c as t,o as r,a4 as o}from"./chunks/framework.ttppV29E.js";const a="/assets/mcp-list-page.DT1PGbPy.png",m=JSON.parse('{"title":"MCP Servers","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mcp-servers/index.md","filePath":"docs/mcp-servers/index.md","lastUpdated":1777544883000}'),n={name:"docs/mcp-servers/index.md"},s=o('<h1 id="mcp-servers" tabindex="-1">MCP Servers <a class="header-anchor" href="#mcp-servers" aria-label="Permalink to &quot;MCP Servers&quot;">​</a></h1><p>MCP (Model Context Protocol) servers allow you to expose AireGlu endpoints as tools and resources that MCP-compatible clients such as Claude.ai, Claude Desktop, Cursor, and other AI-powered applications can discover and invoke.</p><h2 id="tenant-access" tabindex="-1">Tenant Access <a class="header-anchor" href="#tenant-access" aria-label="Permalink to &quot;Tenant Access&quot;">​</a></h2><p>MCP server features are enabled per-tenant. If you don&#39;t see <strong>AI Tools &gt; MCP Servers</strong> in the navigation, contact support to request access for your tenant.</p><h2 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h2><ul><li><strong>MCP Server</strong> - A named configuration containing one or more versions, each exposing a set of endpoints as tools and resources.</li><li><strong>Version</strong> - A semantic version (e.g. <code>1.0.0</code>) within a server. Each version defines its own set of exposed endpoints and can be activated or deactivated independently.</li><li><strong>Default Version</strong> - The version used when an MCP client connects without specifying a version in the URI. Can be set during creation or changed later via the server actions menu.</li><li><strong>Tool</strong> - An endpoint exposed as an invocable action. MCP clients call tools to perform operations (e.g. submit data, trigger a workflow).</li><li><strong>Resource</strong> - An endpoint exposed as readable data. MCP clients read resources to retrieve information (e.g. fetch a dataset, read configuration).</li><li><strong>Connection URI</strong> - The URL an MCP client uses to connect to your server.</li></ul><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>MCP usage requires the following claims on your user account:</p><table><thead><tr><th>Action</th><th>Required Claim</th></tr></thead><tbody><tr><td>View server list</td><td><code>list:McpServerConfig</code></td></tr><tr><td>View server details</td><td><code>view:McpServerConfig</code></td></tr><tr><td>Create a server</td><td><code>create:McpServerConfig</code></td></tr><tr><td>Edit a server</td><td><code>edit:McpServerConfig</code></td></tr><tr><td>Delete a server</td><td><code>delete:McpServerConfig</code></td></tr><tr><td>Connect a client to a server</td><td><code>run:Mcp</code></td></tr></tbody></table><p>The first five claims cover server management in the AireGlu UI. <code>run:Mcp</code> is required to authenticate an MCP client (e.g. Claude.ai, Cursor) against a server - without it the client will complete OAuth login but every tool or resource call will fail.</p><p>Contact your administrator if you do not have the required permissions.</p><h2 id="navigation" tabindex="-1">Navigation <a class="header-anchor" href="#navigation" aria-label="Permalink to &quot;Navigation&quot;">​</a></h2><p>MCP Servers are found under <strong>AI Tools &gt; MCP Servers</strong> in the main navigation.</p><p><img src="'+a+'" alt="mcp"></p>',14),i=[s];function c(d,l,p,u,h,v){return r(),t("div",null,i)}const f=e(n,[["render",c]]);export{m as __pageData,f as default};
